    // ── Test 4: Ping gateway ─────────────────────────────────────────

    let gw = crate::net::gateway_ip();
    total += 1;
    if test_ping(gw, "gateway", false) { passed += 1; }

    // ── Test 5: Ping Google DNS (8.8.8.8) ───────────────────────────
