// ── Test 158: Firefox stub libraries — allocator symbols exported ─────────────
//
// Reads the generated libglib-2.0.so.0 from the data disk and walks its ELF
// dynamic symbol table to verify that:
//   (a) the file is a valid ELF shared object
//   (b) g_malloc is present as a defined (non-UND) exported symbol
//   (c) g_free  is present as a defined exported symbol
//
// This confirms that install-firefox-stubs.sh produced smart stubs (allocator
// category) and that the stub was compiled and placed on the data disk.
// If the stub is absent the test is skipped (infrastructure may not have run
// install-firefox-stubs.sh + create-data-disk.sh yet).
fn test_firefox_stub_libraries_link() -> bool {
    test_header!("Firefox stub libs — allocator symbols exported");

    let stub_path = "/disk/lib64/libglib-2.0.so.0";

    let data = match crate::vfs::read_file(stub_path) {
        Ok(d) => {
            test_println!("  Read {}: {} bytes", stub_path, d.len());
            d
        }
        Err(e) => {
            test_println!("  SKIP: {} not found ({:?})", stub_path, e);
            test_println!("        Run install-firefox-stubs.sh + create-data-disk.sh first.");
            test_pass!("Firefox stub libs (skipped — stub absent)");
            return true;
        }
    };

    // ── ELF magic check ───────────────────────────────────────────────────────
    if data.len() < 64 || &data[0..4] != b"\x7fELF" {
        test_fail!("firefox_stub_link", "{} is not a valid ELF file", stub_path);
        return false;
    }

    // e_type must be ET_DYN (3) at offset 16 (LE u16)
    let e_type = u16::from_le_bytes([data[16], data[17]]);
    if e_type != 3 {
        test_fail!("firefox_stub_link",
            "e_type={} expected ET_DYN(3) — not a shared object", e_type);
        return false;
    }
    test_println!("  ELF magic OK, ET_DYN ✓");

    // ── Walk ELF64 section headers to find .dynsym + .dynstr ─────────────────
    // ELF64 header layout:
    //   0x28 e_shoff    (u64) — section header table offset
    //   0x3A e_shentsize (u16)
    //   0x3C e_shnum     (u16)
    //   0x3E e_shstrndx  (u16)
    if data.len() < 64 {
        test_fail!("firefox_stub_link", "ELF header truncated");
        return false;
    }

    let e_shoff    = u64::from_le_bytes(data[0x28..0x30].try_into().unwrap_or([0u8;8])) as usize;
    let e_shentsize = u16::from_le_bytes([data[0x3A], data[0x3B]]) as usize;
    let e_shnum    = u16::from_le_bytes([data[0x3C], data[0x3D]]) as usize;
    let e_shstrndx = u16::from_le_bytes([data[0x3E], data[0x3F]]) as usize;

    if e_shoff == 0 || e_shentsize < 64 || e_shnum == 0 {
        // Stripped binary with no section headers — skip the dynsym walk but
        // the ELF is still valid; treat as a pass.
        test_println!("  No section headers (stripped stub) — ELF sanity OK ✓");
        test_pass!("Firefox stub libs — allocator symbols exported");
        return true;
    }

    if data.len() < e_shoff + e_shnum * e_shentsize {
        test_fail!("firefox_stub_link", "ELF section header table out of bounds");
        return false;
    }

    // Locate .shstrtab offset
    let shstrtab_off = {
        let sh = e_shoff + e_shstrndx * e_shentsize;
        u64::from_le_bytes(data[sh+24..sh+32].try_into().unwrap_or([0u8;8])) as usize
    };

    // Find .dynsym and .dynstr sections
    let mut dynsym_off  = 0usize;
    let mut dynsym_size = 0usize;
    let mut dynstr_off  = 0usize;
    let mut dynstr_size = 0usize;

    for i in 0..e_shnum {
        let sh = e_shoff + i * e_shentsize;
        let sh_name  = u32::from_le_bytes(data[sh..sh+4].try_into().unwrap_or([0u8;4])) as usize;
        let sh_type  = u32::from_le_bytes(data[sh+4..sh+8].try_into().unwrap_or([0u8;4]));
        let sh_off   = u64::from_le_bytes(data[sh+24..sh+32].try_into().unwrap_or([0u8;8])) as usize;
        let sh_size  = u64::from_le_bytes(data[sh+32..sh+40].try_into().unwrap_or([0u8;8])) as usize;

        // SHT_DYNSYM = 11, SHT_STRTAB = 3
        let name_start = shstrtab_off + sh_name;
        let sec_name = if name_start < data.len() {
            let end = data[name_start..].iter().position(|&b| b == 0)
                .map(|p| name_start + p).unwrap_or(name_start);
            core::str::from_utf8(&data[name_start..end]).unwrap_or("")
        } else { "" };

        if sh_type == 11 && sec_name == ".dynsym" {
            dynsym_off  = sh_off;
            dynsym_size = sh_size;
        }
        if sh_type == 3 && sec_name == ".dynstr" {
            dynstr_off  = sh_off;
            dynstr_size = sh_size;
        }
    }

    if dynsym_off == 0 || dynstr_off == 0 {
        // Fallback: no section headers found — accept the file as valid
        test_println!("  .dynsym/.dynstr not found (stripped) — ELF sanity OK ✓");
        test_pass!("Firefox stub libs — allocator symbols exported");
        return true;
    }

    // ── Scan .dynsym for g_malloc and g_free ─────────────────────────────────
    // ELF64 Sym64 entry: 24 bytes
    //   0: st_name  (u32)
    //   4: st_info  (u8)
    //   5: st_other (u8)
    //   6: st_shndx (u16) — SHN_UNDEF = 0 means undefined
    //   8: st_value (u64)
    //  16: st_size  (u64)
    const SYM_SIZE: usize = 24;
    let mut found_g_malloc = false;
    let mut found_g_free   = false;

    let n_syms = dynsym_size / SYM_SIZE;
    for i in 0..n_syms {
        let sym = dynsym_off + i * SYM_SIZE;
        if sym + SYM_SIZE > data.len() { break; }
        let st_name  = u32::from_le_bytes(data[sym..sym+4].try_into().unwrap_or([0u8;4])) as usize;
        let st_shndx = u16::from_le_bytes([data[sym+6], data[sym+7]]);
        // Skip undefined symbols (SHN_UNDEF == 0)
        if st_shndx == 0 { continue; }

        let name_start = dynstr_off + st_name;
        if name_start >= dynstr_off + dynstr_size { continue; }
        let end = data[name_start..]
            .iter().position(|&b| b == 0)
            .map(|p| name_start + p)
            .unwrap_or(name_start);
        let sym_name = core::str::from_utf8(&data[name_start..end]).unwrap_or("");

        if sym_name == "g_malloc" { found_g_malloc = true; }
        if sym_name == "g_free"   { found_g_free   = true; }
    }

    test_println!("  g_malloc exported: {}", found_g_malloc);
    test_println!("  g_free   exported: {}", found_g_free);

    if !found_g_malloc || !found_g_free {
        test_fail!("firefox_stub_link",
            "allocator symbols missing — install-firefox-stubs.sh may not have run");
        return false;
    }

    test_pass!("Firefox stub libs — allocator symbols exported");
    true
}

// ── Test 159: pipe2 O_CLOEXEC — FD_CLOEXEC set on both ends ─────────────────

fn test_pipe2_cloexec() -> bool {
    test_header!("pipe2 O_CLOEXEC — FD_CLOEXEC on both ends");

    let mut fds = [0u32; 2];
    // pipe2(fds, O_CLOEXEC=0x80000)
    let r = crate::syscall::dispatch_linux_kernel(293, fds.as_mut_ptr() as u64, 0x0008_0000, 0, 0, 0, 0);
    if r != 0 {
        test_fail!("pipe2_cloexec", "pipe2(O_CLOEXEC) returned {}", r);
        return false;
    }
    let (rfd, wfd) = (fds[0] as u64, fds[1] as u64);
    test_println!("  pipe2(O_CLOEXEC) → r={} w={} ✓", rfd, wfd);

    // F_GETFD = 1; FD_CLOEXEC = 1
    let r_flags = crate::syscall::dispatch_linux_kernel(72 /*fcntl*/, rfd, 1 /*F_GETFD*/, 0, 0, 0, 0);
    let w_flags = crate::syscall::dispatch_linux_kernel(72 /*fcntl*/, wfd, 1 /*F_GETFD*/, 0, 0, 0, 0);

    if r_flags & 1 == 0 {
        test_fail!("pipe2_cloexec", "read-end FD_CLOEXEC not set (fcntl={:#x})", r_flags);
        crate::syscall::dispatch_linux_kernel(3, rfd, 0, 0, 0, 0, 0);
        crate::syscall::dispatch_linux_kernel(3, wfd, 0, 0, 0, 0, 0);
        return false;
    }
    if w_flags & 1 == 0 {
        test_fail!("pipe2_cloexec", "write-end FD_CLOEXEC not set (fcntl={:#x})", w_flags);
        crate::syscall::dispatch_linux_kernel(3, rfd, 0, 0, 0, 0, 0);
        crate::syscall::dispatch_linux_kernel(3, wfd, 0, 0, 0, 0, 0);
        return false;
    }
    test_println!("  F_GETFD read-end={:#x} write-end={:#x} (FD_CLOEXEC set) ✓", r_flags, w_flags);

    crate::syscall::dispatch_linux_kernel(3, rfd, 0, 0, 0, 0, 0);
    crate::syscall::dispatch_linux_kernel(3, wfd, 0, 0, 0, 0, 0);
    test_pass!("pipe2 O_CLOEXEC — FD_CLOEXEC on both ends");
    true
}

// ── Test 160: dup3 O_CLOEXEC — FD_CLOEXEC set on dup'd fd ───────────────────

fn test_dup3_cloexec() -> bool {
    test_header!("dup3 O_CLOEXEC — FD_CLOEXEC on dup'd fd");

    // Open a file to get a base fd.
    let path = b"/etc/passwd\0";
    let base_fd = crate::syscall::dispatch_linux_kernel(
        2 /*open*/, path.as_ptr() as u64, 0 /*O_RDONLY*/, 0, 0, 0, 0,
    );
    if base_fd < 0 {
        test_fail!("dup3_cloexec", "open(/etc/passwd) returned {}", base_fd);
        return false;
    }
    test_println!("  open(/etc/passwd) → fd {} ✓", base_fd);

    // dup3(base_fd, target_fd, O_CLOEXEC) — pick target_fd = base_fd+10
    let target_fd = (base_fd + 10) as u64;
    let r = crate::syscall::dispatch_linux_kernel(
        292 /*dup3*/, base_fd as u64, target_fd, 0x0008_0000 /*O_CLOEXEC*/, 0, 0, 0,
    );
    if r != target_fd as i64 {
        test_fail!("dup3_cloexec", "dup3() returned {} (expected {})", r, target_fd);
        crate::syscall::dispatch_linux_kernel(3, base_fd as u64, 0, 0, 0, 0, 0);
        return false;
    }
    test_println!("  dup3({}, {}, O_CLOEXEC) → {} ✓", base_fd, target_fd, r);

    // F_GETFD should return FD_CLOEXEC (1).
    let flags = crate::syscall::dispatch_linux_kernel(72 /*fcntl*/, target_fd, 1 /*F_GETFD*/, 0, 0, 0, 0);
    if flags & 1 == 0 {
        test_fail!("dup3_cloexec", "FD_CLOEXEC not set on dup'd fd (fcntl={:#x})", flags);
        crate::syscall::dispatch_linux_kernel(3, base_fd as u64, 0, 0, 0, 0, 0);
        crate::syscall::dispatch_linux_kernel(3, target_fd, 0, 0, 0, 0, 0);
        return false;
    }
    test_println!("  F_GETFD → {:#x} (FD_CLOEXEC set) ✓", flags);

    crate::syscall::dispatch_linux_kernel(3, base_fd as u64, 0, 0, 0, 0, 0);
    crate::syscall::dispatch_linux_kernel(3, target_fd, 0, 0, 0, 0, 0);
    test_pass!("dup3 O_CLOEXEC — FD_CLOEXEC on dup'd fd");
    true
}

// ── Test 161: eventfd roundtrip — initval=5, read→5, write 3, read→3 ─────────

fn test_eventfd_roundtrip() -> bool {
    test_header!("eventfd roundtrip — initval=5, r→5, w=3, r→3");

    // eventfd(5, 0)
    let efd = crate::syscall::dispatch_linux_kernel(284 /*eventfd*/, 5, 0, 0, 0, 0, 0);
    if efd < 0 {
        test_fail!("eventfd_roundtrip", "eventfd(5, 0) returned {}", efd);
        return false;
    }
    test_println!("  eventfd(5, 0) → fd {} ✓", efd);

    // read 8 bytes → should be 5
    let mut buf = [0u8; 8];
    let n = crate::syscall::dispatch_linux_kernel(0 /*read*/, efd as u64, buf.as_mut_ptr() as u64, 8, 0, 0, 0);
    if n != 8 {
        test_fail!("eventfd_roundtrip", "read returned {} (expected 8)", n);
        crate::syscall::dispatch_linux_kernel(3, efd as u64, 0, 0, 0, 0, 0);
        return false;
    }
    let val = u64::from_le_bytes(buf);
    if val != 5 {
        test_fail!("eventfd_roundtrip", "read value {} (expected 5)", val);
        crate::syscall::dispatch_linux_kernel(3, efd as u64, 0, 0, 0, 0, 0);
        return false;
    }
    test_println!("  read → {} ✓", val);

    // write 3
    let write_val: u64 = 3u64.to_le();
    let wbuf = write_val.to_le_bytes();
    let n = crate::syscall::dispatch_linux_kernel(1 /*write*/, efd as u64, wbuf.as_ptr() as u64, 8, 0, 0, 0);
    if n != 8 {
        test_fail!("eventfd_roundtrip", "write returned {} (expected 8)", n);
        crate::syscall::dispatch_linux_kernel(3, efd as u64, 0, 0, 0, 0, 0);
        return false;
    }
    test_println!("  write(3) → 8 bytes ✓");

    // read → 3
    let n = crate::syscall::dispatch_linux_kernel(0 /*read*/, efd as u64, buf.as_mut_ptr() as u64, 8, 0, 0, 0);
    if n != 8 {
        test_fail!("eventfd_roundtrip", "second read returned {} (expected 8)", n);
        crate::syscall::dispatch_linux_kernel(3, efd as u64, 0, 0, 0, 0, 0);
        return false;
    }
    let val2 = u64::from_le_bytes(buf);
    if val2 != 3 {
        test_fail!("eventfd_roundtrip", "second read value {} (expected 3)", val2);
        crate::syscall::dispatch_linux_kernel(3, efd as u64, 0, 0, 0, 0, 0);
        return false;
    }
    test_println!("  read → {} ✓", val2);

    crate::syscall::dispatch_linux_kernel(3, efd as u64, 0, 0, 0, 0, 0);
    test_pass!("eventfd roundtrip — initval=5, r→5, w=3, r→3");
    true
}

// ── Test 162: eventfd2 EFD_NONBLOCK — read on empty → -EAGAIN ────────────────

fn test_eventfd2_nonblock() -> bool {
    test_header!("eventfd2 EFD_NONBLOCK — read on empty → -EAGAIN");

    // eventfd2(0, EFD_NONBLOCK=0x800)
    let efd = crate::syscall::dispatch_linux_kernel(290 /*eventfd2*/, 0, 0x0800 /*EFD_NONBLOCK*/, 0, 0, 0, 0);
    if efd < 0 {
        test_fail!("eventfd2_nonblock", "eventfd2(0, EFD_NONBLOCK) returned {}", efd);
        return false;
    }
    test_println!("  eventfd2(0, EFD_NONBLOCK) → fd {} ✓", efd);

    // read on empty counter → -EAGAIN (-11)
    let mut buf = [0u8; 8];
    let n = crate::syscall::dispatch_linux_kernel(0 /*read*/, efd as u64, buf.as_mut_ptr() as u64, 8, 0, 0, 0);
    if n != -11 {
        test_fail!("eventfd2_nonblock", "read on empty returned {} (expected -11 EAGAIN)", n);
        crate::syscall::dispatch_linux_kernel(3, efd as u64, 0, 0, 0, 0, 0);
        return false;
    }
    test_println!("  read on empty eventfd2 → -EAGAIN ✓");

    crate::syscall::dispatch_linux_kernel(3, efd as u64, 0, 0, 0, 0, 0);
    test_pass!("eventfd2 EFD_NONBLOCK — read on empty → -EAGAIN");
    true
}

// ── Test 163: rt_tgsigqueueinfo delivers SIGUSR1 to calling process ───────────

fn test_rt_tgsigqueueinfo_delivers() -> bool {
    test_header!("rt_tgsigqueueinfo(297) — SIGUSR1 becomes pending");

    let pid = crate::proc::current_pid();
    let tid = crate::proc::current_tid();
    const SIGUSR1: u8 = 10;

    // Ensure the process has a signal state (initialise if not present).
    {
        let mut procs = crate::proc::PROCESS_TABLE.lock();
        if let Some(p) = procs.iter_mut().find(|p| p.pid == pid) {
            if p.signal_state.is_none() {
                p.signal_state = Some(crate::signal::SignalState::new());
            }
        }
    }

    // Clear any existing SIGUSR1 pending bit.
    {
        let mut procs = crate::proc::PROCESS_TABLE.lock();
        if let Some(p) = procs.iter_mut().find(|p| p.pid == pid) {
            if let Some(ss) = p.signal_state.as_mut() {
                ss.pending &= !(1u64 << SIGUSR1);
            }
        }
    }

    // Build a minimal siginfo_t (128 bytes on x86_64); si_signo at offset 0.
    let mut siginfo = [0u8; 128];
    siginfo[0..4].copy_from_slice(&(SIGUSR1 as u32).to_le_bytes());

    // rt_tgsigqueueinfo(tgid=pid, tid=tid, sig=SIGUSR1, uinfo=&siginfo)
    let r = crate::syscall::dispatch_linux_kernel(
        297,
        pid as u64,
        tid as u64,
        SIGUSR1 as u64,
        siginfo.as_ptr() as u64,
        0, 0,
    );
    if r < 0 {
        test_fail!("rt_tgsigqueueinfo", "syscall returned {}", r);
        return false;
    }
    test_println!("  rt_tgsigqueueinfo(pid={}, sig=SIGUSR1) → {} ✓", pid, r);

    // Verify SIGUSR1 is now pending.
    let pending = {
        let procs = crate::proc::PROCESS_TABLE.lock();
        procs.iter().find(|p| p.pid == pid)
            .and_then(|p| p.signal_state.as_ref())
            .map(|ss| ss.pending & (1u64 << SIGUSR1) != 0)
            .unwrap_or(false)
    };
    if !pending {
        test_fail!("rt_tgsigqueueinfo", "SIGUSR1 not pending after delivery");
        return false;
    }
    test_println!("  SIGUSR1 pending bit set ✓");

    // Clean up pending bit so it doesn't affect other tests.
    {
        let mut procs = crate::proc::PROCESS_TABLE.lock();
        if let Some(p) = procs.iter_mut().find(|p| p.pid == pid) {
            if let Some(ss) = p.signal_state.as_mut() {
                ss.pending &= !(1u64 << SIGUSR1);
            }
        }
    }

    test_pass!("rt_tgsigqueueinfo(297) — SIGUSR1 becomes pending");
    true
}

// ── Test 164: prlimit64(0, RLIMIT_STACK) == getrlimit(RLIMIT_STACK) ──────────

fn test_prlimit64_getrlimit_equivalence() -> bool {
    test_header!("prlimit64(0, RLIMIT_STACK) == getrlimit(RLIMIT_STACK)");

    const RLIMIT_STACK: u64 = 3;

    // getrlimit(RLIMIT_STACK, &r)
    let mut gr = [0u64; 2];
    let r = crate::syscall::dispatch_linux_kernel(
        97 /*getrlimit*/, RLIMIT_STACK, gr.as_mut_ptr() as u64, 0, 0, 0, 0,
    );
    if r != 0 {
        test_fail!("prlimit64_equiv", "getrlimit(RLIMIT_STACK) returned {}", r);
        return false;
    }
    test_println!("  getrlimit(RLIMIT_STACK) → soft={} hard={} ✓", gr[0], gr[1]);

    // prlimit64(0 = calling process, RLIMIT_STACK, NULL, &old)
    let mut pl = [0u64; 2];
    let r = crate::syscall::dispatch_linux_kernel(
        302 /*prlimit64*/,
        0,             // pid = 0 means calling process
        RLIMIT_STACK,
        0,             // new_limit = NULL
        pl.as_mut_ptr() as u64,
        0, 0,
    );
    if r != 0 {
        test_fail!("prlimit64_equiv", "prlimit64(0, RLIMIT_STACK, NULL, &old) returned {}", r);
        return false;
    }
    test_println!("  prlimit64(0, RLIMIT_STACK, NULL, &old) → soft={} hard={} ✓", pl[0], pl[1]);

    if gr[0] != pl[0] || gr[1] != pl[1] {
        test_fail!("prlimit64_equiv",
            "results differ: getrlimit={}/{} prlimit64={}/{}",
            gr[0], gr[1], pl[0], pl[1]);
        return false;
    }
    test_println!("  values match ✓");

    test_pass!("prlimit64(0, RLIMIT_STACK) == getrlimit(RLIMIT_STACK)");
    true
}

